import importlib.resources as _ir
resource_filename = lambda pkg, path: str(_ir.files(pkg).joinpath(path))

import gi
gi.require_version('Gtk', '3.0')  # @UndefinedVariable
from gi.repository import Gtk  # @UnresolvedImport

import matplotlib
from matplotlib.figure import Figure
from matplotlib.backends.backend_gtk3cairo import FigureCanvasGTK3Cairo as FigureCanvasGTK
from matplotlib.backends.backend_gtk3 import NavigationToolbar2GTK3 as NavigationToolbar

from pyxrd.generic.views import BaseView

class RefinerView(BaseView):
    """
        A view for the Refiner object
    """
    
    builder = resource_filename(__name__, "glade/refine_results.glade")
    top = "window_refine_results"
    modal = True

    graph_parent = "plot_box"

    def __init__(self, *args, **kwargs):
        BaseView.__init__(self, *args, **kwargs)

        self.graph_parent = self[self.graph_parent]

        self.get_toplevel().set_transient_for(self.parent.get_toplevel())

        self.setup_matplotlib_widget()

    def update_labels(self, initial, best, last, elapsed=None):
        self["initial_residual"].set_text("%f" % initial)
        self["best_residual"].set_text("%f" % best)
        self["last_residual"].set_text("%f" % last)
        if elapsed is not None:
            mins, secs = divmod(int(elapsed), 60)
            self["elapsed_time"].set_text("%d:%02d" % (mins, secs))

    def setup_matplotlib_widget(self):
        # TODO Create a mixin for this kind of thing!!
        #style = Gtk.Style()
        self.figure = Figure(dpi=96)

        self.figure.subplots_adjust(left=0.12, right=0.88, top=0.92, bottom=0.12, hspace=0.4, wspace=0.4)

        self.canvas = FigureCanvasGTK(self.figure)

        box = Gtk.VBox()
        box.pack_start(NavigationToolbar(self.canvas), False, True, 0)
        box.pack_start(self.canvas, True, True, 0)
        self.graph_parent.add(box)
        self.graph_parent.show_all()

        cdict = {'red': ((0.0, 0.0, 0.0),
                         (0.5, 1.0, 1.0),
                         (1.0, 0.0, 0.0)),
                'green': ((0.0, 0.0, 0.0),
                         (0.5, 1.0, 1.0),
                         (1.0, 0.0, 0.0)),
                'blue': ((0.0, 0.0, 0.0),
                         (0.5, 1.0, 1.0),
                         (1.0, 0.0, 0.0))}
        self.wbw_cmap = matplotlib.colors.LinearSegmentedColormap('WBW', cdict, 256)

    def show_plot_popup(self):
        import io
        from gi.repository import GdkPixbuf

        buf = io.BytesIO()
        self.figure.savefig(buf, format='png', dpi=150, bbox_inches='tight')
        buf.seek(0)

        loader = GdkPixbuf.PixbufLoader.new_with_type('png')
        loader.write(buf.read())
        loader.close()
        pixbuf = loader.get_pixbuf()

        image = Gtk.Image.new_from_pixbuf(pixbuf)

        scroll = Gtk.ScrolledWindow()
        scroll.set_policy(Gtk.PolicyType.AUTOMATIC, Gtk.PolicyType.AUTOMATIC)
        scroll.add(image)

        win = Gtk.Window(title="Parameter space")
        win.set_default_size(1200, 900)
        win.set_transient_for(self.get_toplevel())
        win.add(scroll)
        win.show_all()

    pass # end of class